mapper.select:
SELECT ca.appointment_id, ca.student_id, u.real_name as student_name, cs.counselor_id, cu.real_name as counselor_name, ca.schedule_id, DATE(cs.schedule_date) as appointment_date, CONCAT(cs.start_time, '-', cs.end_time) as appointment_time, ca.appointment_type, ca.consultation_mode, ca.location, ca.appointment_status, ca.cancellation_reason, ca.cancelled_by, ca.is_urgent, ca.notes, ca.created_at, ca.updated_at FROM consultation_appointment ca LEFT JOIN counselor_schedule cs ON ca.schedule_id = cs.schedule_id LEFT JOIN user u ON ca.student_id = u.user_id LEFT JOIN counselor_info ci ON cs.counselor_id = ci.counselor_id LEFT JOIN user cu ON ci.counselor_id = cu.user_id
AND ca.student_id = #{userId}
AND cs.counselor_id = #{counselorId}
AND ca.appointment_status = #{status}
ORDER BY ca.created_at DESC
